using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 changed the default discriminator property from
            // "Discriminator" to "$type". Preserve the old name so existing
            // documents (and direct SQL queries that reference c.Discriminator)
            // continue to work.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed the id format from "Product|123" to "123".
            // Preserve the old compound format so existing 500K documents
            // remain readable without a data migration.
            entity.HasRootDiscriminatorInJsonId(true);
        });

        // HasIndex removed — Cosmos DB does not support EF-managed indexes.
        // Manage indexing policy via the Azure Portal, Bicep, or Terraform.
    }
}
