using System.Linq;
using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async System.Threading.Tasks.Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still references c.Discriminator (preserved via
        // HasDiscriminator("Discriminator") in OnModelCreating).
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9 Cosmos provider no longer supports sync I/O; use async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

